INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(9, 1, '10', '추세분석', '문서에서 기술적 분석의 제1 원칙으로 제시된 격언은?', '"저점 매수, 고점 매도(Buy Low, Sell High)"', '"추세를 따라가라(Trend is your friend)"', '"분산투자가 최선이다(Diversification is key)"', '"시장을 이길 수 없다(You cannot beat the market)"', 2, '문서에서 기술적 분석의 제1 원칙으로 "추세를 따라가라(Trend is your friend)"를 제시합니다.'),
(9, 2, '10', '추세분석', '문서에서 상승추세(Uptrend)의 정의로 제시된 것은?', '가격이 일정 범위 내에서 등락을 반복한다', '고점과 저점이 연속해서 높아진다(HH·HL)', '고점과 저점이 연속해서 낮아진다(LH·LL)', '거래량이 지속적으로 증가하는 상태이다', 2, '문서 추세의 세 가지 종류 표에서 상승추세(Uptrend)는 고점과 저점이 연속해서 높아지는(HH·HL) 상태라고 정의합니다.'),
(9, 3, '10', '추세분석', '문서에서 하락추세(Downtrend) 시 매매 관점으로 제시된 것은?', '추세 방향으로 매수한다', '박스권 상하단 역매매를 한다', '현금 보유 또는 공매도를 한다', '지지선에서 적극 매수한다', 3, '문서 추세의 세 가지 종류 표에서 하락추세 시 매매 관점은 현금 보유 또는 공매도라고 설명합니다.'),
(9, 4, '10', '추세분석', '문서에서 추세선 긋는 실전 규칙 중 종가 기준으로 추세선을 이탈했을 때의 해석은?', '일시적 조정으로 보고 추가 매수한다', '추세 전환으로 본다', '거래량 확인 후 재판단한다', '피보나치 되돌림 레벨과 비교한다', 2, '문서 추세선 긋는 법 실전 규칙 3에서 종가 기준으로 추세선 이탈 시 추세 전환으로 본다고 설명합니다.'),
(9, 5, '10', '추세분석', '문서에서 ADX > 25일 때의 의미는?', '추세가 없어 횡보 중임을 나타낸다', '강한 추세가 존재함을 나타낸다', '과매수 구간에 진입했음을 나타낸다', '골든크로스 발생 직전 신호이다', 2, '문서 추세 강도 판단 표에서 ADX > 25는 강한 추세 존재를 의미하고, ADX < 20은 추세 없음(횡보)을 의미한다고 설명합니다.'),
(9, 6, '10', '추세분석', '문서에서 이동평균 정배열(상승 강세)의 구조로 제시된 것은?', 'MA5 < MA20 < MA60 < MA200', 'MA200 > MA60 > MA20 > MA5', 'MA5 > MA20 > MA60 > MA200', 'MA20 > MA5 > MA60 > MA200', 3, '문서에서 정배열(상승 강세)은 MA5 > MA20 > MA60 > MA200 순서라고 설명합니다.'),
(9, 7, '10', '추세분석', '문서의 실전 추세 분석 6단계에서 Step 1에 해당하는 내용은?', '추세선 + 채널 그리기(저점 2개 이상 연결)', 'ADX + 거래량으로 추세 강도 검증', '월봉·주봉으로 대추세 확인(상승/하락/횡보)', '일봉으로 현재 추세 방향과 강도 확인', 3, '문서 실전 추세 분석 6단계 프로세스에서 Step 1은 월봉·주봉으로 대추세를 확인하는 것이라고 설명합니다.'),
(9, 8, '10', '지지선·저항선', '문서에서 지지선(Support)의 정의로 제시된 것은?', '올라가다가 자주 막히는 구간으로 매도 세력이 모이는 가격대', '가격이 내려오다가 자주 멈추는 구간으로 매수 세력이 모이는 가격대', '추세선과 평행하게 그어 가격 통로를 표시한 선', '골든크로스 발생 이후 형성되는 수평 가격대', 2, '문서에서 지지선은 가격이 내려오다가 자주 멈추는 구간으로 매수 세력이 모이는 가격대라고 정의합니다.'),
(9, 9, '10', '지지선·저항선', '문서에서 설명하는 지지선과 저항선의 "역할 전환"이란 무엇인가?', '지지선이 새로운 저항선이 되고, 저항선이 새로운 지지선이 된다', '돌파된 저항선은 이후 지지선으로, 붕괴된 지지선은 이후 저항선으로 바뀐다', '지지선은 항상 저항선보다 낮은 가격대에 위치한다', '추세 전환 후 지지선과 저항선이 동시에 이동한다', 2, '문서에서 역할 전환은 돌파된 저항선은 이후 지지선으로, 붕괴된 지지선은 이후 저항선으로 바뀌는 경우가 많다고 설명합니다.'),
(9, 10, '10', '지지선·저항선', '문서에서 가격이 저항선을 거래량 급증과 함께 돌파했을 때의 대응으로 제시된 것은?', '지지 붕괴로 보고 목표가를 하향한다', '일시적 노이즈로 보고 관망한다', '돌파 신뢰로 보고 매수 진입 또는 목표가를 상향한다', '피보나치 되돌림을 적용하고 대기한다', 3, '문서 지지선·저항선 실전 활용법 표에서 가격이 저항선 돌파 + 거래량 급증 시 돌파 신뢰로 보고 매수 진입 또는 목표가 상향을 검토한다고 설명합니다.'),
(9, 11, '10', '이동평균선', '문서에서 MA20의 기간과 용도로 제시된 것은?', '5일, 단기 모멘텀', '20일, 월간 추세', '60일, 분기 추세', '200일, 장기 추세 기준선', 2, '문서 이동평균선 표에서 MA20은 20일 기간으로 월간 추세를 파악하는 데 사용한다고 설명합니다.'),
(9, 12, '10', '이동평균선', '문서에서 골든크로스(Golden Cross)의 정의로 제시된 것은?', '단기선(MA20)이 장기선(MA60)을 아래로 돌파하는 것', '장기선(MA200)이 단기선(MA20) 위로 올라오는 것', '단기선(MA20)이 장기선(MA60)을 위로 돌파하는 것', 'MA5와 MA20이 동일한 값을 가지는 시점', 3, '문서에서 골든크로스는 단기선(MA20)이 장기선(MA60)을 위로 돌파하는 것으로 상승 추세 전환 신호라고 설명합니다.'),
(9, 13, '10', '이동평균선', '문서에서 골든크로스 발생 시 거래량이 동반되지 않았을 때의 해석은?', '매수 신호 신뢰도가 높아 즉시 매수한다', '노이즈 가능성이 있어 지지선 확인 후 진입을 검토한다', '데드크로스가 임박한 신호로 매도를 준비한다', '피보나치 61.8% 레벨까지 기다린다', 2, '문서 골든크로스·데드크로스 발생 시나리오 다이어그램에서 거래량 미동반 시 노이즈 가능성으로 보고 지지선 확인 후 진입을 검토한다고 설명합니다.'),
(9, 14, '10', '이동평균선', '문서에서 MA20·MA60 골든크로스와 MA5·MA20 골든크로스를 비교한 설명은?', 'MA5·MA20 골든크로스가 더 신뢰도가 높고 느리다', 'MA20·MA60 골든크로스가 중기 추세 전환 신호로 신뢰도가 높다', 'MA5·MA20 골든크로스가 장기 추세 전환을 의미한다', 'MA20·MA60 골든크로스는 단기 매수에 더 적합하다', 2, '문서 이동평균 활용 표에서 MA5·MA20 골든크로스는 단기 매수 신호이나 노이즈가 많고, MA20·MA60 골든크로스는 중기 추세 전환 신호로 신뢰도가 높다고 설명합니다.'),
(9, 15, '10', '갭(Gap) 분석', '문서에서 갭(Gap)의 정의로 제시된 것은?', '이동평균선과 볼린저밴드 사이의 가격 구간', '전날 종가와 다음 날 시가 사이에 가격이 크게 비어 있는 구간', 'RSI 70 이상에서 형성되는 과매수 구간', '추세선과 가격 사이에 생기는 빈 공간', 2, '문서에서 갭은 전날 종가와 다음 날 시가 사이에 가격이 크게 비어 있는 구간이라고 정의합니다.'),
(9, 16, '10', '갭(Gap) 분석', '문서에서 돌파 갭(Breakaway Gap)의 특징으로 제시된 것은?', '추세 중간에 발생하며 추세 지속 신호이다', '추세 끝에서 마지막 힘으로 발생하는 추세 마감 경고이다', '박스권·저항선 돌파 후 발생하며 강한 추세 시작 신호이다', '작은 갭으로 빠르게 메워지는 일시적 수급 불균형이다', 3, '문서 갭 종류 표에서 돌파 갭(Breakaway)은 박스권·저항선 돌파 후 발생하며 강한 추세 시작 신호라고 설명합니다.'),
(9, 17, '10', '갭(Gap) 분석', '문서의 갭 상승 후 체크리스트에서 "소진갭 가능성"을 확인하는 항목은?', '거래량이 평균의 2배 이상인가?', '갭 발생 전 박스권 상단을 돌파했는가?', '다음 날 갭을 메우려는 시도가 있는가?', '갭 발생 후 5일 내 갭을 완전히 메우는가?', 3, '문서 갭 상승 후 체크리스트에서 다음 날 갭을 메우려는 시도가 있는가를 확인하면 소진갭 가능성을 판단할 수 있다고 설명합니다.'),
(9, 18, '10', '피보나치 되돌림', '문서에서 피보나치 되돌림의 "황금비율"로 불리는 레벨과 그 의미는?', '23.6%, 약한 조정 후 지지', '38.2%, 일반적 조정의 지지', '50.0%, 심리적 중간점', '61.8%, 강력한 지지·저항', 4, '문서 주요 피보나치 되돌림 레벨 표에서 61.8%를 황금비율로 칭하며 강력한 지지·저항 레벨이라고 설명합니다.'),
(9, 19, '10', '피보나치 되돌림', '문서에서 피보나치 되돌림이 38.2%일 때의 추세 강도와 대응으로 제시된 것은?', '매우 강한 상승 추세, 추격 매수 가능', '건강한 조정, 눌림목 매수 적기', '추세 확인 구간, 신중한 매수', '추세 약화 가능성, 손절 후 관망', 2, '문서 되돌림 깊이 표에서 38.2% 되돌림은 건강한 조정으로 눌림목 매수 적기라고 설명합니다.'),
(9, 20, '10', '피보나치 되돌림', '문서의 피보나치 되돌림 실전 예시에서 주가가 50,000→80,000원으로 상승 후 61.8% 되돌림이 적용되는 지지 가격은?', '약 68,540원', '약 65,000원', '약 61,460원', '약 58,090원', 3, '문서 되돌림 실전 예시에서 61.8% 되돌림 = 80,000 - (80,000-50,000)×0.618 = 61,460원이 강한 지지라고 계산합니다.'),
(9, 21, '10', 'RSI', '문서에서 RSI(상대강도지수)의 계산 공식으로 제시된 것은?', 'RSI = 14일 평균 상승폭 × 14일 평균 하락폭', 'RSI = 100 × RS / (1 + RS)', 'RSI = 100 - 100 / (1 + RS), RS = 14일 평균 상승폭 / 14일 평균 하락폭', 'RSI = (종가 - 14일 최저가) / (14일 최고가 - 14일 최저가) × 100', 3, '문서에서 RSI = 100 - 100 / (1 + RS), RS = 14일 평균 상승폭 / 14일 평균 하락폭으로 정의합니다.'),
(9, 22, '10', 'RSI', '문서에서 RSI > 70인 과매수 구간에서 ADX < 20(추세 약함)일 때의 대응은?', '과매수 유지 가능으로 추세 추종을 유지한다', '조정 임박 경고로 분할 매도 또는 익절을 검토한다', '반등 매수를 검토하고 지지선 겹침을 확인한다', '손절 후 관망 전략을 유지한다', 2, '문서 RSI 신호 판단 흐름 다이어그램에서 RSI > 70이고 추세 약함(ADX < 20) 시 조정 임박 경고로 분할 매도 또는 익절을 검토한다고 설명합니다.'),
(9, 23, '10', 'RSI', '문서에서 RSI < 30인 과매도 구간에서 횡보·상승 추세일 때의 대응은?', '추세 추종 하락으로 반등 시 매도 대기', '반등 매수를 검토하고 지지선 겹침을 확인해야 한다', '피보나치 38.2% 레벨까지 기다린다', '골든크로스 발생 후 매수한다', 2, '문서 RSI 신호 판단 흐름에서 RSI < 30이고 횡보·상승 추세 시 반등 매수를 검토하되 지지선 겹침 확인이 필수라고 설명합니다.'),
(9, 24, '10', 'MACD', '문서에서 MACD의 계산 공식으로 제시된 것은?', 'MACD = EMA26 - EMA12, Signal = MACD의 12일 EMA', 'MACD = EMA12 - EMA26, Signal = MACD의 9일 EMA', 'MACD = MA20 - MA60, Signal = MACD의 9일 SMA', 'MACD = EMA9 - EMA26, Signal = MACD의 12일 EMA', 2, '문서에서 MACD = EMA12 - EMA26, Signal = MACD의 9일 EMA, 히스토그램 = MACD - Signal로 정의합니다.'),
(9, 25, '10', 'MACD', '문서에서 MACD 히스토그램이 0선을 음수→양수로 상향 돌파했을 때의 의미는?', '매도 신호로 MACD가 Signal 아래로 내려간다', '하락 모멘텀이 강화되어 현금을 보유한다', '매수 신호로 MACD가 Signal 위로 올라간다', '과매수 구간으로 분할 매도를 검토한다', 3, '문서 MACD 신호 판단 흐름에서 히스토그램이 0선 상향 돌파(음→양 전환) 시 매수 신호로 MACD가 Signal 위에 위치한다고 설명합니다.'),
(9, 26, '10', 'MACD', '문서에서 가격은 상승(↑)하는데 MACD는 하락(↓)하는 경우를 가리키는 용어와 그 의미는?', '상승 다이버전스, 강한 매수 신호', '하락 다이버전스, 추세 약화 경고로 매도 준비', '골든크로스, 추세 전환 신호', '소진갭, 추세 마감 경고', 2, '문서 MACD 신호 판단 흐름에서 가격↑ MACD↓는 하락 다이버전스로 추세 약화 경고 및 매도 준비를 나타낸다고 설명합니다.'),
(9, 27, '10', '볼린저밴드', '문서에서 볼린저밴드 상단밴드의 계산 공식으로 제시된 것은?', '상단밴드 = MA20 - 2σ', '상단밴드 = MA20 × 1.02', '상단밴드 = MA20 + 2σ(표준편차)', '상단밴드 = EMA20 + 2 × ATR', 3, '문서에서 볼린저밴드 상단밴드 = MA20 + 2σ(표준편차), 하단밴드 = MA20 - 2σ로 정의합니다.'),
(9, 28, '10', '볼린저밴드', '문서에서 볼린저밴드 폭이 좁아지는(수렴) 현상의 의미는?', '추세가 강하게 지속될 것임을 나타낸다', '변동성이 축소되어 곧 큰 움직임을 예고한다', '과매수 구간에 진입했음을 의미한다', '데드크로스 발생이 임박했음을 의미한다', 2, '문서에서 볼린저밴드 폭이 좁아지는 수렴은 변동성 축소로 곧 큰 움직임을 예고한다고 설명합니다.'),
